const userStoryName = $('Save user story details and test strategy prompt').item.json.userStoryTitle;
const tcId = $('Set data for generating outcome').item.json.tcId;
const tcName = $('Set data for generating outcome').item.json.tcName;

const steps = $('Set data for generating outcome').item.json.steps;
const expOutput = $json.output.expectedOutcome;

// funkcja usuwająca numerację typu "1. ", "2. " itd.
const cleanStep = (text) => {
  return text.replace(/^\d+\.\s*/, '');
};

// mapowanie step -> expectedOutcome
const mappedSteps = steps.map((step, index) => {
  return {
    name: cleanStep(step),
    expectedOutcome: cleanStep(expOutput[index] || "")
  };
});

return {
  json: {
    userStoryName,
    tcId,
    tcName,
    steps: mappedSteps
  }
};

parameters.inputSchema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "ManualTestCases",
  "type": "array",
  "minItems": 1,
  "maxItems": 20,
  "items": {
    "type": "object",
    "properties": {
      "tcId": {
        "type": "string",
        "description": "Unique identifier for the test case, e.g., TC01",
        "pattern": "^TC\\d{2}$"
      },
      "tcName": {
        "type": "string",
        "description": "Descriptive name of the test case"
      },
      "steps": {
        "type": "array",
        "description": "List of steps as strings",
        "items": {
          "type": "string",
          "description": "Description of a single step, e.g., '1. Click login button'"
        },
        "minItems": 1
      }
    },
    "required": ["tcId", "tcName", "steps"],
    "additionalProperties": false
  }
}

{
  "type": "object",
  "properties": {
    "expectedOutcome": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "List of expected outcomes corresponding 1:1 to steps"
    }
  },
  "required": ["expectedOutcome"]
}
